Concrete C++ implementation of Kadane (non-empty array, handles all-negative correctly, uses long long for overflow safety):

#include <vector>
#include <algorithm>

long long max_subarray_sum(const std::vector<long long>& a) {
    // Precondition: a is non-empty.
    long long current = a[0];
    long long best    = a[0];
    for (size_t i = 1; i < a.size(); ++i) {
        current = std::max(a[i], current + a[i]);
        best    = std::max(best, current);
    }
    return best;
}

Concrete C++ implementation of Floyd's two-phase algorithm. Returns the cycle-start node, or nullptr if no cycle exists.

struct ListNode { int val; ListNode* next; };

ListNode* detect_cycle_start(ListNode* head) {
    // Phase 1: detect a cycle.
    ListNode* slow = head;
    ListNode* fast = head;
    while (fast != nullptr && fast->next != nullptr) {
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast) {
            // Phase 2: find the cycle start.
            ListNode* probe = head;
            while (probe != slow) {
                probe = probe->next;
                slow  = slow->next;
            }
            return probe;
        }
    }
    return nullptr;  // no cycle
}

Concrete C++ implementation of binary search on a sorted vector. Returns the index of target, or -1 if not present. Uses the overflow-safe midpoint and the inclusive [lo, hi] invariant.

#include <vector>

int binary_search(const std::vector<int>& a, int target) {
    int lo = 0;
    int hi = static_cast<int>(a.size()) - 1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (a[mid] == target) return mid;
        if (a[mid] < target) lo = mid + 1;
        else                 hi = mid - 1;
    }
    return -1;
}

Numeric-safety idiom: declare accumulators that can exceed roughly 2 * 10^9 as `long long`, and force long-long arithmetic in mixed expressions with the `1LL` literal so the multiplication promotes BOTH operands to 64-bit before computing.

using ll = long long;
ll sum = 0;
sum += 1LL * a[i] * b[i];   // both a[i] and b[i] are promoted to long long first
ll big = (ll)x * y;          // explicit cast variant

Bit trick that extracts the lowest set bit of an integer: `i & -i`. It is the engine of Fenwick-tree index traversal because adding or subtracting the lowest set bit walks between a Fenwick node and its parent.

// move toward larger indices (point update direction)
for (int i = idx; i <= n; i += i & -i) { /* ... */ }
// move toward smaller indices (prefix query direction)
for (int i = idx; i > 0;  i -= i & -i) { /* ... */ }

Fenwick (Binary Indexed Tree) supporting O(log n) point updates and O(log n) prefix-sum queries on an array of length n. Uses 1-based internal indexing; the wrapper accepts 0-based positions by adding 1 at the boundary.

#include <vector>
struct Fenwick {
    int n;
    std::vector<long long> bit;
    Fenwick(int n_) : n(n_), bit(n_ + 1, 0) {}
    // point update: a[i] += delta   (i is 1-based)
    void update(int i, long long delta) {
        for (; i <= n; i += i & -i) bit[i] += delta;
    }
    // prefix sum a[1..i]
    long long query(int i) {
        long long s = 0;
        for (; i > 0; i -= i & -i) s += bit[i];
        return s;
    }
    // inclusive range sum a[l..r], 1-based
    long long range(int l, int r) {
        return query(r) - query(l - 1);
    }
};

Static prefix-sum array: O(n) build, O(1) range query, no updates. Use `long long` for the prefix array if individual values can be larger than ~10^4 and n is large.

#include <vector>
std::vector<long long> pref(n + 1, 0);
for (int i = 0; i < n; ++i) pref[i + 1] = pref[i] + a[i];
long long range_sum = pref[r + 1] - pref[l];   // inclusive [l, r], both 0-based

Difference-array technique for many range-add updates followed by ONE final reconstruction: O(1) per add, O(n) at the end.

#include <vector>
std::vector<long long> diff(n + 1, 0);
auto add = [&](int l, int r, long long v) {   // inclusive [l, r], 0-based
    diff[l]     += v;
    diff[r + 1] -= v;
};
// ... apply many add() calls ...
std::vector<long long> a(n);
long long run = 0;
for (int i = 0; i < n; ++i) {
    run += diff[i];
    a[i] = run;
}

BFS on a 4-connected grid, returning shortest-step distance from a single source. `-1` marks unreachable; `'#'` marks blocked cells.

#include <vector>
#include <queue>
#include <utility>
int H = grid.size(), W = grid[0].size();
std::vector<std::vector<int>> dist(H, std::vector<int>(W, -1));
std::queue<std::pair<int,int>> q;
q.push({sr, sc});
dist[sr][sc] = 0;
const int dr[4] = {-1, 1, 0, 0};
const int dc[4] = { 0, 0,-1, 1};
while (!q.empty()) {
    auto [r, c] = q.front(); q.pop();
    for (int k = 0; k < 4; ++k) {
        int nr = r + dr[k], nc = c + dc[k];
        if (nr < 0 || nr >= H || nc < 0 || nc >= W) continue;
        if (dist[nr][nc] != -1 || grid[nr][nc] == '#') continue;
        dist[nr][nc] = dist[r][c] + 1;
        q.push({nr, nc});
    }
}

Dijkstra with a min-heap (std::priority_queue + std::greater). Works on graphs with non-negative edge weights. `adj[u]` is a vector of (neighbor, weight) pairs.

#include <vector>
#include <queue>
#include <climits>
using P = std::pair<long long, int>;   // (distance, node)
std::vector<long long> dist(n, LLONG_MAX);
std::priority_queue<P, std::vector<P>, std::greater<P>> pq;
dist[src] = 0;
pq.push({0, src});
while (!pq.empty()) {
    auto [d, u] = pq.top(); pq.pop();
    if (d > dist[u]) continue;             // stale heap entry
    for (auto [v, w] : adj[u]) {
        if (d + w < dist[v]) {
            dist[v] = d + w;
            pq.push({dist[v], v});
        }
    }
}

Topological-order DP via Kahn's algorithm (BFS over zero-in-degree frontier). The example counts paths from `src` modulo MOD; replace the recurrence with whatever DP the problem needs.

#include <vector>
#include <queue>
const long long MOD = 1'000'000'007LL;
std::vector<int> indeg(n, 0);
for (int u = 0; u < n; ++u)
    for (int v : adj[u]) ++indeg[v];
std::queue<int> q;
for (int u = 0; u < n; ++u)
    if (indeg[u] == 0) q.push(u);
std::vector<long long> dp(n, 0);
dp[src] = 1;
while (!q.empty()) {
    int u = q.front(); q.pop();
    for (int v : adj[u]) {
        dp[v] = (dp[v] + dp[u]) % MOD;
        if (--indeg[v] == 0) q.push(v);
    }
}

Precompute factorials and inverse factorials modulo a prime so that nCr can be answered in O(1) per query. Inverse factorials are derived from the top down using the identity inv_fact[i] = inv_fact[i+1] * (i+1).

#include <vector>
const long long MOD = 1'000'000'007LL;
auto pw = [](long long a, long long e, long long m) {
    long long r = 1 % m; a %= m;
    while (e) {
        if (e & 1) r = r * a % m;
        a = a * a % m;
        e >>= 1;
    }
    return r;
};
std::vector<long long> fact(N + 1), inv_fact(N + 1);
fact[0] = 1;
for (int i = 1; i <= N; ++i) fact[i] = fact[i - 1] * i % MOD;
inv_fact[N] = pw(fact[N], MOD - 2, MOD);
for (int i = N - 1; i >= 0; --i)
    inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD;
auto nCr = [&](int n, int r) -> long long {
    if (r < 0 || r > n) return 0;
    return fact[n] * inv_fact[r] % MOD * inv_fact[n - r] % MOD;
};
